// Hook to inject SEO meta tags dynamically
function useSEO(page) {
  useEffect(() => {
    const seo = SEO[page] || SEO.accueil;
    document.title = seo.title;

    const setMeta = (name, content, attr = "name") => {
      let el = document.querySelector(`meta[${attr}="${name}"]`);
      if (!el) {
        el = document.createElement("meta");
        el.setAttribute(attr, name);
        document.head.appendChild(el);
      }
      el.setAttribute("content", content);
    };

    setMeta("description", seo.description);
    setMeta("robots", "index, follow, max-snippet:-1, max-image-preview:large");
    setMeta("author", "Noya Châteaudun");
    setMeta("geo.region", "FR-75");
    setMeta("geo.placename", "Paris");

    // Open Graph
    setMeta("og:title", seo.title, "property");
    setMeta("og:description", seo.description, "property");
    setMeta("og:type", page === "accueil" ? "website" : "article", "property");
    setMeta("og:url", seo.canonical, "property");
    setMeta("og:site_name", "Noya Châteaudun", "property");
    setMeta("og:locale", "fr_FR", "property");
    setMeta("og:image", `${SITE_URL}/images/noya-og.jpg`, "property");
    setMeta("og:image:width", "1200", "property");
    setMeta("og:image:height", "630", "property");
    setMeta("og:image:alt", "Noya Châteaudun, restaurant méditerranéen et levant, Paris 9e", "property");

    // Twitter
    setMeta("twitter:card", "summary_large_image");
    setMeta("twitter:title", seo.title);
    setMeta("twitter:description", seo.description);

    // Canonical
    let canonical = document.querySelector('link[rel="canonical"]');
    if (!canonical) {
      canonical = document.createElement("link");
      canonical.setAttribute("rel", "canonical");
      document.head.appendChild(canonical);
    }
    canonical.setAttribute("href", seo.canonical);

    // Lang
    document.documentElement.lang = "fr";

    // JSON-LD Restaurant (only on accueil)
    let ldRestaurant = document.getElementById("noya-jsonld");
    if (page === "accueil") {
      if (!ldRestaurant) {
        ldRestaurant = document.createElement("script");
        ldRestaurant.id = "noya-jsonld";
        ldRestaurant.type = "application/ld+json";
        document.head.appendChild(ldRestaurant);
      }
      ldRestaurant.textContent = JSON.stringify(STRUCTURED_DATA);
    } else if (ldRestaurant) {
      ldRestaurant.remove();
    }

    // JSON-LD Breadcrumb (all pages)
    const breadcrumbNames = {
      accueil: "Accueil",
      "la-carte": "La Carte",
      galerie: "Galerie",
      "notre-histoire": "Notre Histoire",
      traiteur: "Traiteur",
      "nous-trouver": "Nous Trouver",
    };
    let ldBreadcrumb = document.getElementById("noya-breadcrumb");
    if (!ldBreadcrumb) {
      ldBreadcrumb = document.createElement("script");
      ldBreadcrumb.id = "noya-breadcrumb";
      ldBreadcrumb.type = "application/ld+json";
      document.head.appendChild(ldBreadcrumb);
    }
    const breadcrumbData = {
      "@context": "https://schema.org",
      "@type": "BreadcrumbList",
      itemListElement: [
        { "@type": "ListItem", position: 1, name: "Accueil", item: SITE_URL },
      ],
    };
    if (page !== "accueil") {
      breadcrumbData.itemListElement.push({
        "@type": "ListItem",
        position: 2,
        name: breadcrumbNames[page] || page,
        item: `${SITE_URL}/${page}`,
      });
    }
    ldBreadcrumb.textContent = JSON.stringify(breadcrumbData);

    // JSON-LD FoodEstablishment menu (on la-carte)
    let ldMenu = document.getElementById("noya-menu-ld");
    if (page === "la-carte") {
      if (!ldMenu) {
        ldMenu = document.createElement("script");
        ldMenu.id = "noya-menu-ld";
        ldMenu.type = "application/ld+json";
        document.head.appendChild(ldMenu);
      }
      ldMenu.textContent = JSON.stringify({
        "@context": "https://schema.org",
        "@type": "Menu",
        name: "Carte Noya Châteaudun",
        description: "Cuisine levantine fait maison : pitas, falafels, houmous, shakshuka, mezze. Options végétariennes, végan et sans gluten.",
        hasMenuSection: [
          {
            "@type": "MenuSection",
            name: "Carte du Midi",
            description: "Service du lundi au vendredi, 11h45 à 15h00",
          },
          {
            "@type": "MenuSection",
            name: "Carte du Soir",
            description: "Les saveurs du Levant sous les lumières de Paris",
          },
        ],
      });
    } else if (ldMenu) {
      ldMenu.remove();
    }

    // JSON-LD CateringService (on traiteur)
    let ldCatering = document.getElementById("noya-catering-ld");
    if (page === "traiteur") {
      if (!ldCatering) {
        ldCatering = document.createElement("script");
        ldCatering.id = "noya-catering-ld";
        ldCatering.type = "application/ld+json";
        document.head.appendChild(ldCatering);
      }
      ldCatering.textContent = JSON.stringify({
        "@context": "https://schema.org",
        "@type": "FoodService",
        name: "Noya Châteaudun, Service Traiteur",
        description: "Service traiteur méditerranéen et levant pour événements privés, mariages, séminaires. Plateaux sur mesure à Paris.",
        provider: {
          "@type": "Restaurant",
          name: "Noya Châteaudun",
          address: { "@type": "PostalAddress", streetAddress: "8 rue de Châteaudun", addressLocality: "Paris", postalCode: "75009", addressCountry: "FR" },
        },
        areaServed: { "@type": "City", name: "Paris" },
      });
    } else if (ldCatering) {
      ldCatering.remove();
    }
  }, [page]);
}

