// ─── NAVBAR ────────────────────────────────────────────────────

const Navbar = ({ currentPage, setPage, scrolled }) => {
  const [mobileOpen, setMobileOpen] = useState(false);
  const navItems = [
    { label: "Accueil", page: "accueil" },
    { label: "La Carte", page: "la-carte" },
    { label: "Galerie", page: "galerie" },
    { label: "Notre Histoire", page: "notre-histoire" },
    { label: "Traiteur", page: "traiteur" },
    { label: "Nous Trouver", page: "nous-trouver" },
  ];
  const navigate = (page) => {
    setPage(page);
    setMobileOpen(false);
    
  };

  return (
    <>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Cormorant+Garamond:ital,wght@0,300;0,400;0,500;0,600;0,700;1,300;1,400;1,500&family=Lato:wght@300;400;700&family=Playfair+Display:ital,wght@0,400;0,500;0,600;0,700;1,400;1,500&display=swap');
        * { margin: 0; padding: 0; box-sizing: border-box; }
        html { scroll-behavior: auto; }
        body { font-family: 'Lato', sans-serif; background: ${COLORS.warmWhite}; color: ${COLORS.dark}; overflow-x: hidden; }
        a { color: inherit; text-decoration: none; -webkit-tap-highlight-color: transparent; }
        button { -webkit-tap-highlight-color: transparent; }
        ::selection { background: ${COLORS.burgundy}; color: ${COLORS.cream}; }

        /* Tablet: hide desktop nav, show mobile menu */
        @media (max-width: 968px) {
          .desktop-nav { display: none !important; }
          .mobile-menu-btn { display: block !important; }
        }

        /* Responsive grids */
        .grid-signatures,
        .grid-commander,
        .grid-reviews,
        .grid-traiteur-types { display: grid; gap: 20px; align-items: stretch; }

        .grid-signatures { grid-template-columns: repeat(auto-fit, minmax(240px, 1fr)); }
        .grid-commander { grid-template-columns: repeat(auto-fit, minmax(220px, 1fr)); gap: 18px; }
        .grid-reviews { grid-template-columns: repeat(auto-fit, minmax(260px, 1fr)); }
        .grid-traiteur-types { grid-template-columns: repeat(auto-fit, minmax(240px, 1fr)); }
        .grid-carte { display: grid; grid-template-columns: repeat(auto-fit, minmax(300px, 1fr)); gap: 28px; align-items: stretch; }
        .grid-galerie { display: grid; grid-template-columns: repeat(auto-fill, minmax(260px, 1fr)); gap: 16px; }
        .grid-form { display: grid; grid-template-columns: repeat(auto-fit, minmax(240px, 1fr)); gap: 16px; margin-bottom: 16px; }
        .grid-contact { display: grid; grid-template-columns: repeat(auto-fit, minmax(280px, 1fr)); gap: 40px; align-items: stretch; }
        .grid-footer { display: grid; grid-template-columns: repeat(auto-fit, minmax(200px, 1fr)); gap: 36px; }

        /* Force equal-height grid children (Reveal wrappers) */
        .grid-signatures > div,
        .grid-commander > div,
        .grid-reviews > div,
        .grid-traiteur-types > div,
        .grid-carte > div { display: flex; flex-direction: column; height: 100%; }
        .grid-signatures > div > div,
        .grid-commander > div > a,
        .grid-reviews > div > div,
        .grid-traiteur-types > div > div,
        .grid-carte > div > a { flex: 1; display: flex; flex-direction: column; }

        /* Bottom bar responsive */
        .bottom-bar-inner { display: flex; justify-content: center; gap: 12px; }
        .bottom-bar-btn { flex: 1; max-width: 220px; }

        /* Lightbox arrows - touch-friendly */
        .lb-arrow { padding: 16px; cursor: pointer; color: ${COLORS.cream}; opacity: 0.8; transition: opacity 0.2s; -webkit-tap-highlight-color: transparent; }
        .lb-arrow:active { opacity: 1; }

        /* Tablet adjustments */
        @media (max-width: 1024px) {
          .grid-carte { grid-template-columns: repeat(auto-fit, minmax(260px, 1fr)); gap: 20px; }
          .grid-galerie { grid-template-columns: repeat(auto-fill, minmax(220px, 1fr)); }
        }

        /* Mobile adjustments */
        @media (max-width: 600px) {
          .grid-signatures { grid-template-columns: 1fr; }
          .grid-commander { grid-template-columns: 1fr; }
          .grid-reviews { grid-template-columns: 1fr; }
          .grid-traiteur-types { grid-template-columns: 1fr; }
          .grid-carte { grid-template-columns: 1fr; }
          .grid-galerie { grid-template-columns: repeat(2, 1fr); gap: 10px; }
          .grid-form { grid-template-columns: 1fr; }
          .grid-contact { grid-template-columns: 1fr; gap: 28px; }
          .grid-footer { grid-template-columns: 1fr 1fr; gap: 24px; }
          .bottom-bar-btn { max-width: none; }
          .hero-section { padding: 0 16px !important; min-height: 90vh !important; }
          .ratings-row { flex-direction: column; gap: 16px !important; }
          .ratings-divider { width: 40px !important; height: 1px !important; }
          .lightbox-card { max-width: 92vw !important; aspect-ratio: 3/4 !important; }
          .filter-row { gap: 6px !important; }
          .filter-row button { padding: 8px 14px !important; font-size: 10px !important; min-height: 36px; }
          .form-container { padding: 28px 20px !important; }
          .stats-row { gap: 20px !important; }
          .stats-row > div { min-width: 80px; }
          .lb-arrow { padding: 20px; }
          /* iOS zoom prevention */
          input, select, textarea { font-size: 16px !important; }
        }

        /* Very small mobile */
        @media (max-width: 380px) {
          .grid-galerie { grid-template-columns: repeat(2, 1fr); gap: 8px; }
          .grid-footer { grid-template-columns: 1fr; }
          .bottom-bar-inner { flex-direction: column; gap: 8px; }
          .bottom-bar-btn { max-width: none; }
        }
      `}</style>
      <nav
        aria-label="Navigation principale"
        role="navigation"
        style={{
          position: "fixed", top: 0, left: 0, right: 0, zIndex: 1000,
          background: scrolled ? `${COLORS.warmWhite}ee` : "transparent",
          backdropFilter: scrolled ? "blur(20px) saturate(1.2)" : "none",
          borderBottom: scrolled ? `1px solid ${COLORS.creamDark}88` : "1px solid transparent",
          transition: "all 0.5s ease",
          padding: "0 clamp(20px, 5vw, 60px)",
        }}
      >
        <div style={{ maxWidth: 1200, margin: "0 auto", display: "flex", alignItems: "center", justifyContent: "space-between", height: 72 }}>
          <div
            onClick={() => navigate("accueil")}
            style={{ cursor: "pointer" }}
          >
            <NoyaLogo height={26} />
          </div>
          <div style={{ display: "flex", alignItems: "center", gap: 28 }} className="desktop-nav">
            {navItems.map((item) => (
              <span
                key={item.page}
                onClick={() => navigate(item.page)}
                style={{
                  cursor: "pointer", fontSize: 12, fontWeight: 400, letterSpacing: 1.8, textTransform: "uppercase",
                  color: currentPage === item.page ? COLORS.burgundy : COLORS.taupe,
                  transition: "all 0.3s", padding: "4px 0",
                  borderBottom: currentPage === item.page ? `1.5px solid ${COLORS.burgundy}` : "1.5px solid transparent",
                }}
                onMouseEnter={(e) => { if (currentPage !== item.page) e.target.style.color = COLORS.dark; }}
                onMouseLeave={(e) => { if (currentPage !== item.page) e.target.style.color = COLORS.taupe; }}
              >
                {item.label}
              </span>
            ))}
            <a
              href={LINKS.reservation}
              target="_blank"
              rel="noopener noreferrer"
              aria-label="Réserver une table chez Noya"
              style={{
                background: COLORS.burgundy, color: COLORS.cream, padding: "10px 22px",
                fontSize: 11, fontWeight: 700, letterSpacing: 2.5, textTransform: "uppercase", transition: "all 0.3s",
              }}
              onMouseEnter={(e) => { e.target.style.background = COLORS.burgundyLight; }}
              onMouseLeave={(e) => { e.target.style.background = COLORS.burgundy; }}
            >
              Réserver
            </a>
          </div>
          <div
            style={{ display: "none", cursor: "pointer", color: COLORS.burgundy }}
            className="mobile-menu-btn"
            onClick={() => setMobileOpen(!mobileOpen)}
            aria-label={mobileOpen ? "Fermer le menu" : "Ouvrir le menu"}
            role="button"
            tabIndex={0}
          >
            {mobileOpen ? <Icons.close /> : <Icons.menu />}
          </div>
        </div>
        {/* Mobile overlay */}
        {mobileOpen && (
          <div
            style={{
              position: "fixed", top: 0, left: 0, width: "100%", height: "100vh",
              background: COLORS.cream, zIndex: 999,
              display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", gap: 28,
            }}
          >
            <div onClick={() => setMobileOpen(false)} style={{ position: "absolute", top: 24, right: 24, cursor: "pointer", color: COLORS.burgundy }}>
              <Icons.close />
            </div>
            <div style={{ marginBottom: 20 }}><NoyaLogo height={38} /></div>
            {navItems.map((item) => (
              <span
                key={item.page}
                onClick={() => navigate(item.page)}
                style={{
                  cursor: "pointer", fontSize: 16, fontWeight: 300, letterSpacing: 4, textTransform: "uppercase",
                  color: currentPage === item.page ? COLORS.burgundy : COLORS.dark,
                }}
              >
                {item.label}
              </span>
            ))}
            <a
              href={LINKS.reservation}
              target="_blank"
              rel="noopener noreferrer"
              style={{
                background: COLORS.burgundy, color: COLORS.cream, padding: "14px 40px", marginTop: 12,
                fontSize: 13, fontWeight: 700, letterSpacing: 2.5, textTransform: "uppercase",
              }}
            >
              Réserver
            </a>
          </div>
        )}
      </nav>
    </>
  );
};

