// ─── PAGE: GALERIE ─────────────────────────────────────────────

const PageGalerie = () => {
  const [activeFilter, setActiveFilter] = useState("all");
  const [lightboxId, setLightboxId] = useState(null);

  const photos = [
    { id: 1, cat: "plats", label: "Pita Of signature", color: COLORS.terracotta, src: PHOTOS.pita_of },
    { id: 2, cat: "plats", label: "Assiette Falafel", color: COLORS.sage, src: PHOTOS.assiette_falafel },
    { id: 3, cat: "plats", label: "Houmous Bilameh", color: COLORS.gold, src: PHOTOS.houmous_bilameh },
    { id: 4, cat: "plats", label: "The Shakshuka", color: COLORS.burgundy, src: PHOTOS.shakshuka },
    { id: 5, cat: "plats", label: "Shakshuka Veggie", color: COLORS.deepTerra, src: PHOTOS.shakshuka_veggie },
    { id: 6, cat: "plats", label: "Labaneh", color: COLORS.deepTerra, src: PHOTOS.labaneh },
    { id: 7, cat: "plats", label: "Malabi", color: COLORS.terracotta, src: PHOTOS.malabi },
    { id: 8, cat: "interieur", label: "Devanture", color: COLORS.terracotta, src: PHOTOS.devanture },
    { id: 9, cat: "interieur", label: "Terrasse & zellige", color: COLORS.gold, src: PHOTOS.terrasse_zellige },
    { id: 10, cat: "interieur", label: "Détails & déco", color: COLORS.sage, src: PHOTOS.deco_etagere },
    { id: 11, cat: "equipe", label: "En cuisine", color: COLORS.burgundy, src: PHOTOS.en_cuisine },
  ];

  const filters = [
    { key: "all", label: "Tout" },
    { key: "plats", label: "Nos Plats" },
    { key: "interieur", label: "Le Restaurant" },
    { key: "equipe", label: "L'Équipe" },
  ];

  const filtered = activeFilter === "all" ? photos : photos.filter((p) => p.cat === activeFilter);
  const lightboxIdx = filtered.findIndex((p) => p.id === lightboxId);
  const lightbox = lightboxIdx >= 0 ? filtered[lightboxIdx] : null;

  return (
    <section style={{ minHeight: "100vh", paddingTop: 72 }}>
      <div style={{ padding: "100px clamp(20px,5vw,60px) 50px", textAlign: "center", position: "relative", background: `radial-gradient(ellipse 100% 100% at 50% 0%, ${COLORS.cream} 0%, ${COLORS.warmWhite} 100%)` }}>
        <WarmGrain />
        <Reveal>
          <div style={{ fontSize: 10, fontWeight: 700, letterSpacing: 4, textTransform: "uppercase", color: COLORS.gold, marginBottom: 14 }}>Noya en images</div>
          <h1 style={{ fontFamily: "'Playfair Display', serif", fontSize: "clamp(38px,7vw,60px)", color: COLORS.burgundy, fontWeight: 400 }}>Galerie</h1>
        </Reveal>
        <Reveal delay={0.12}>
          <Divider />
          <p style={{ fontFamily: "'Cormorant Garamond', serif", fontSize: "clamp(17px,2.2vw,21px)", color: COLORS.taupe, maxWidth: 520, margin: "0 auto", lineHeight: 1.85, fontWeight: 300 }}>
            L'ambiance, les saveurs, les sourires. Découvrez l'univers Noya à travers notre galerie.
          </p>
        </Reveal>
        <Reveal delay={0.2}>
          <div className="filter-row" style={{ display: "flex", gap: 10, justifyContent: "center", marginTop: 32, flexWrap: "wrap" }}>
            {filters.map((f) => (
              <button
                key={f.key}
                onClick={() => setActiveFilter(f.key)}
                style={{
                  padding: "8px 20px", fontSize: 11, fontWeight: activeFilter === f.key ? 700 : 400,
                  letterSpacing: 1.8, textTransform: "uppercase", cursor: "pointer",
                  border: `1.5px solid ${activeFilter === f.key ? COLORS.burgundy : COLORS.creamDark}`,
                  background: activeFilter === f.key ? COLORS.burgundy : "transparent",
                  color: activeFilter === f.key ? COLORS.cream : COLORS.taupe,
                  transition: "all 0.3s", fontFamily: "'Lato', sans-serif",
                }}
              >
                {f.label}
              </button>
            ))}
          </div>
        </Reveal>
      </div>

      <div style={{ padding: "30px clamp(20px,5vw,60px) 100px", maxWidth: 1100, margin: "0 auto" }}>
        <div className="grid-galerie">
          {filtered.map((photo, i) => (
            <Reveal key={photo.id} delay={i * 0.04}>
              <div
                onClick={() => setLightboxId(photo.id)}
                style={{
                  position: "relative",
                  overflow: "hidden",
                  aspectRatio: "3/4",
                  background: photo.src ? COLORS.dark : `linear-gradient(135deg, ${photo.color}18 0%, ${photo.color}08 100%)`,
                  border: `1px solid ${COLORS.creamDark}`,
                  transition: "all 0.5s",
                  cursor: "pointer",
                }}
                onMouseEnter={(e) => { e.currentTarget.style.transform = "translateY(-4px)"; e.currentTarget.style.boxShadow = `0 16px 40px ${COLORS.dark}10`; }}
                onMouseLeave={(e) => { e.currentTarget.style.transform = "none"; e.currentTarget.style.boxShadow = "none"; }}
              >
                {photo.src ? (
                  <>
                    <img src={photo.src} alt={photo.label} loading="lazy" style={{ position: "absolute", inset: 0, width: "100%", height: "100%", objectFit: "cover" }} />
                    <div style={{ position: "absolute", bottom: 0, left: 0, right: 0, padding: "40px 16px 14px", background: "linear-gradient(transparent, rgba(0,0,0,0.5))" }}>
                      <span style={{ fontFamily: "'Cormorant Garamond', serif", fontSize: 15, color: "#fff", fontStyle: "italic" }}>{photo.label}</span>
                    </div>
                  </>
                ) : (
                  <div style={{
                    position: "absolute", inset: 0, display: "flex", flexDirection: "column",
                    alignItems: "center", justifyContent: "center", padding: 24,
                  }}>
                    <div style={{
                      width: 56, height: 56, borderRadius: "50%",
                      border: `1.5px solid ${photo.color}44`,
                      display: "flex", alignItems: "center", justifyContent: "center",
                      marginBottom: 14,
                    }}>
                      <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke={photo.color} strokeWidth="1.2">
                        {photo.cat === "interieur" && <><rect x="3" y="5" width="18" height="14" rx="2" /><polyline points="3 15 8 10 13 15" /><polyline points="14 13 17 10 21 14" /><circle cx="17" cy="8" r="1.5" fill={photo.color} /></>}
                        {photo.cat === "equipe" && <><circle cx="12" cy="8" r="4" /><path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2" /></>}
                      </svg>
                    </div>
                    <span style={{ fontFamily: "'Cormorant Garamond', serif", fontSize: 16, fontStyle: "italic", color: photo.color, textAlign: "center" }}>{photo.label}</span>
                    <span style={{ fontSize: 9, letterSpacing: 2, textTransform: "uppercase", color: COLORS.taupe, marginTop: 6 }}>Photo à ajouter</span>
                  </div>
                )}
              </div>
            </Reveal>
          ))}
        </div>
      </div>

      {/* Instagram */}
      <InstagramCTA background={COLORS.cream} />

      {/* Lightbox overlay */}
      {lightbox && (
        <div
          onClick={() => setLightboxId(null)}
          onTouchStart={(e) => { e.currentTarget._touchX = e.touches[0].clientX; }}
          onTouchEnd={(e) => {
            const dx = e.changedTouches[0].clientX - (e.currentTarget._touchX || 0);
            const idx = lightboxIdx;
            if (dx < -50 && idx < filtered.length - 1) setLightboxId(filtered[idx + 1].id);
            else if (dx > 50 && idx > 0) setLightboxId(filtered[idx - 1].id);
          }}
          style={{
            position: "fixed", inset: 0, zIndex: 2000,
            background: `${COLORS.dark}ee`,
            backdropFilter: "blur(20px)",
            display: "flex", alignItems: "center", justifyContent: "center",
            padding: 24,
            animation: "lbIn 0.3s ease forwards",
          }}
        >
          <style>{`
            @keyframes lbIn { from { opacity: 0; } to { opacity: 1; } }
            @keyframes lbScale { from { opacity: 0; transform: scale(0.92); } to { opacity: 1; transform: scale(1); } }
          `}</style>
          {/* Close button */}
          <div onClick={(e) => { e.stopPropagation(); setLightboxId(null); }} className="lb-arrow" style={{ position: "absolute", top: 12, right: 12 }}>
            <Icons.close />
          </div>
          {/* Nav arrows */}
          {lightboxIdx > 0 && (
            <div
              onClick={(e) => { e.stopPropagation(); setLightboxId(filtered[lightboxIdx - 1].id); }}
              className="lb-arrow"
              style={{ position: "absolute", left: 4, top: "50%", transform: "translateY(-50%) rotate(180deg)" }}
            >
              <Icons.arrow />
            </div>
          )}
          {lightboxIdx < filtered.length - 1 && (
            <div
              onClick={(e) => { e.stopPropagation(); setLightboxId(filtered[lightboxIdx + 1].id); }}
              className="lb-arrow"
              style={{ position: "absolute", right: 4, top: "50%", transform: "translateY(-50%)" }}
            >
              <Icons.arrow />
            </div>
          )}
          <div
            onClick={(e) => e.stopPropagation()}
            className="lightbox-card"
            style={{
              maxWidth: 560, width: "100%", aspectRatio: lightbox.src ? "auto" : "3/4",
              background: lightbox.src ? "transparent" : `linear-gradient(135deg, ${lightbox.color}22 0%, ${lightbox.color}08 100%)`,
              border: lightbox.src ? "none" : `1px solid ${lightbox.color}33`,
              display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center",
              animation: "lbScale 0.35s ease forwards",
              overflow: "hidden",
            }}
          >
            {lightbox.src ? (
              <>
                <img src={lightbox.src} alt={lightbox.label} style={{ width: "100%", maxHeight: "80vh", objectFit: "contain", borderRadius: 2 }} />
                <div style={{ padding: "14px 0 4px", textAlign: "center" }}>
                  <span style={{ fontFamily: "'Playfair Display', serif", fontSize: 20, color: COLORS.cream }}>{lightbox.label}</span>
                  <div style={{ fontSize: 12, color: `${COLORS.cream}44`, marginTop: 8 }}>{lightboxIdx + 1} / {filtered.length}</div>
                </div>
              </>
            ) : (
              <>
                <div style={{
                  width: 72, height: 72, borderRadius: "50%",
                  border: `1.5px solid ${lightbox.color}55`,
                  display: "flex", alignItems: "center", justifyContent: "center", marginBottom: 20,
                }}>
                  <svg width="32" height="32" viewBox="0 0 24 24" fill="none" stroke={lightbox.color} strokeWidth="1.2">
                    {lightbox.cat === "interieur" && <><rect x="3" y="5" width="18" height="14" rx="2" /><polyline points="3 15 8 10 13 15" /><polyline points="14 13 17 10 21 14" /><circle cx="17" cy="8" r="1.5" fill={lightbox.color} /></>}
                    {lightbox.cat === "equipe" && <><circle cx="12" cy="8" r="4" /><path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2" /></>}
                  </svg>
                </div>
                <span style={{ fontFamily: "'Playfair Display', serif", fontSize: 24, color: lightbox.color, marginBottom: 6 }}>{lightbox.label}</span>
                <span style={{ fontSize: 11, letterSpacing: 2, textTransform: "uppercase", color: `${COLORS.cream}66` }}>Photo à ajouter</span>
                <div style={{ fontSize: 12, color: `${COLORS.cream}44`, marginTop: 20 }}>{lightboxIdx + 1} / {filtered.length}</div>
              </>
            )}
          </div>
        </div>
      )}
    </section>
  );
};

// ─── FIXED BOTTOM BAR ──────────────────────────────────────────

const BottomBar = () => {
  const [orderOpen, setOrderOpen] = useState(false);
  const [barVisible, setBarVisible] = useState(true);
  const lastScrollY = useRef(0);

  useEffect(() => {
    const handleScroll = () => {
      const y = window.scrollY;
      if (y > lastScrollY.current + 10 && y > 200) {
        setBarVisible(false);
        setOrderOpen(false);
      } else if (y < lastScrollY.current - 5) {
        setBarVisible(true);
      }
      lastScrollY.current = y;
    };
    window.addEventListener("scroll", handleScroll, { passive: true });
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  return (
    <>
      <div
        role="toolbar"
        aria-label="Commander ou réserver"
        style={{
          position: "fixed", bottom: 0, left: 0, right: 0, zIndex: 900,
          background: `${COLORS.warmWhite}ee`,
          backdropFilter: "blur(16px) saturate(1.2)",
          borderTop: `1px solid ${COLORS.creamDark}88`,
          padding: "10px clamp(16px, 4vw, 40px)",
          display: "flex", justifyContent: "center", gap: 12,
          transform: barVisible ? "translateY(0)" : "translateY(100%)",
          transition: "transform 0.4s cubic-bezier(0.4, 0, 0.2, 1)",
        }}
      >
        <button
          className="bottom-bar-btn"
          onClick={() => setOrderOpen(!orderOpen)}
          aria-label="Commander en ligne. À emporter, Deliveroo, Uber Eats"
          aria-expanded={orderOpen}
          style={{
            flex: 1, maxWidth: 220, padding: "12px 20px",
            background: "transparent", border: `1.5px solid ${COLORS.burgundy}`,
            color: COLORS.burgundy, fontSize: 11, fontWeight: 700,
            letterSpacing: 2, textTransform: "uppercase",
            cursor: "pointer", transition: "all 0.3s",
            fontFamily: "'Lato', sans-serif",
            display: "flex", alignItems: "center", justifyContent: "center", gap: 8,
          }}
          onMouseEnter={(e) => { e.currentTarget.style.background = COLORS.burgundy; e.currentTarget.style.color = COLORS.cream; }}
          onMouseLeave={(e) => { e.currentTarget.style.background = "transparent"; e.currentTarget.style.color = COLORS.burgundy; }}
        >
          <Icons.external /> Commander
        </button>
        <a
          className="bottom-bar-btn"
          href={LINKS.reservation}
          target="_blank"
          rel="noopener noreferrer"
          style={{
            flex: 1, maxWidth: 220, padding: "12px 20px",
            background: COLORS.burgundy, color: COLORS.cream,
            fontSize: 11, fontWeight: 700, letterSpacing: 2, textTransform: "uppercase",
            transition: "all 0.3s", textAlign: "center",
            display: "flex", alignItems: "center", justifyContent: "center", gap: 8,
          }}
          onMouseEnter={(e) => { e.currentTarget.style.background = COLORS.burgundyLight; }}
          onMouseLeave={(e) => { e.currentTarget.style.background = COLORS.burgundy; }}
        >
          Réserver
        </a>
      </div>

      {/* Order options popup */}
      {orderOpen && (
        <div
          style={{
            position: "fixed", bottom: 56, left: 0, right: 0, zIndex: 899,
            display: "flex", justifyContent: "center", padding: "0 16px",
          }}
        >
          <div
            style={{
              background: COLORS.warmWhite, border: `1px solid ${COLORS.creamDark}`,
              boxShadow: `0 -8px 30px ${COLORS.dark}12`,
              padding: "16px 20px", maxWidth: 460, width: "100%",
              display: "flex", gap: 10, flexWrap: "wrap", justifyContent: "center",
            }}
          >
            {[
              { label: "À Emporter", url: LINKS.emporter, color: COLORS.terracotta },
              { label: "Deliveroo", url: LINKS.deliveroo, color: "#00CCBC" },
              { label: "Uber Eats", url: LINKS.uberEats, color: "#06C167" },
            ].map((item) => (
              <a
                key={item.label}
                href={item.url}
                target="_blank"
                rel="noopener noreferrer"
                style={{
                  flex: "1 1 120px", padding: "10px 16px", textAlign: "center",
                  border: `1px solid ${COLORS.creamDark}`, fontSize: 11,
                  fontWeight: 700, letterSpacing: 1.5, textTransform: "uppercase",
                  color: item.color, transition: "all 0.3s",
                }}
                onMouseEnter={(e) => { e.currentTarget.style.borderColor = item.color; e.currentTarget.style.background = `${item.color}08`; }}
                onMouseLeave={(e) => { e.currentTarget.style.borderColor = COLORS.creamDark; e.currentTarget.style.background = "transparent"; }}
              >
                {item.label}
              </a>
            ))}
            <div
              onClick={() => setOrderOpen(false)}
              style={{
                width: "100%", textAlign: "center", paddingTop: 8,
                fontSize: 10, color: COLORS.taupe, cursor: "pointer",
                letterSpacing: 1.5, textTransform: "uppercase",
              }}
            >
              Fermer
            </div>
          </div>
        </div>
      )}

      {/* Click outside to close */}
      {orderOpen && (
        <div
          onClick={() => setOrderOpen(false)}
          style={{ position: "fixed", inset: 0, zIndex: 898, background: `${COLORS.dark}22` }}
        />
      )}
    </>
  );
};

// ─── MAIN APP ──────────────────────────────────────────────────

export default function NoyaWebsite() {
  const [currentPage, setCurrentPage] = useState("accueil");
  const [scrolled, setScrolled] = useState(false);
  const [pageVisible, setPageVisible] = useState(true);
  const [pendingPage, setPendingPage] = useState(null);

  useSEO(currentPage);

  // Smooth page transition
  const navigateTo = (page) => {
    if (page === currentPage) return;
    setPageVisible(false);
    setPendingPage(page);
  };

  useEffect(() => {
    if (pendingPage && !pageVisible) {
      const t = setTimeout(() => {
        setCurrentPage(pendingPage);
        setPendingPage(null);
        // Force scroll to top with multiple methods
        window.scrollTo(0, 0);
        document.documentElement.scrollTop = 0;
        document.body.scrollTop = 0;
        // Also scroll after a frame to ensure new content is rendered
        requestAnimationFrame(() => {
          window.scrollTo(0, 0);
          document.documentElement.scrollTop = 0;
          document.body.scrollTop = 0;
          setPageVisible(true);
        });
      }, 350);
      return () => clearTimeout(t);
    }
  }, [pendingPage, pageVisible]);

  useEffect(() => {
    const handleScroll = () => setScrolled(window.scrollY > 50);
    window.addEventListener("scroll", handleScroll);
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  const renderPage = () => {
    switch (currentPage) {
      case "la-carte": return <PageLaCarte />;
      case "galerie": return <PageGalerie />;
      case "notre-histoire": return <PageNotreHistoire />;
      case "traiteur": return <PageTraiteur />;
      case "nous-trouver": return <PageNousTrouver />;
      case "mentions-legales": return <PageMentionsLegales />;
      default: return <PageAccueil setPage={navigateTo} />;
    }
  };

  const pageLabels = {
    accueil: "Page d'accueil Noya Châteaudun",
    "la-carte": "La carte du restaurant",
    galerie: "Galerie photos",
    "notre-histoire": "Notre histoire",
    traiteur: "Service traiteur",
    "nous-trouver": "Informations pratiques et plan d'accès",
    "mentions-legales": "Mentions légales",
  };

  return (
    <div style={{ minHeight: "100vh", background: COLORS.warmWhite, paddingBottom: 56 }}>
      <Navbar currentPage={currentPage} setPage={navigateTo} scrolled={scrolled} />
      <main
        role="main"
        aria-label={pageLabels[currentPage] || "Contenu principal"}
        style={{
          opacity: pageVisible ? 1 : 0,
          transform: pageVisible ? "none" : "translateY(12px)",
          transition: "opacity 0.35s ease, transform 0.35s ease",
        }}
      >
        {renderPage()}
      </main>
      <Footer setPage={navigateTo} />
      <BottomBar />
    </div>
  );
}
